const expectedToken = 'REPLACE_WITH_RABBIT_TOKEN';

function parsePayload(input) {
  const direct = input.payload ?? input.body?.payload ?? input.body ?? input;
  if (typeof direct === 'string') {
    try { return JSON.parse(direct); } catch (error) { return { token: direct }; }
  }
  return direct || {};
}

const payload = parsePayload($json);
const token = String(payload.token || payload.apiKey || payload.key || '').trim();
const tokenConfigured = expectedToken && !expectedToken.startsWith('REPLACE_WITH_');
const valid = Boolean(tokenConfigured && token === expectedToken);

return [{
  json: {
    valid,
    revoked: !valid,
    status: valid ? 'ok' : 'revoked',
    reply: valid ? 'Consultando costes OpenAI.' : 'Token revocado o invalido.',
    source: String(payload.source || 'rabbit-r1-openai-status'),
    sentAt: payload.sentAt || '',
    receivedAt: new Date().toISOString()
  }
}];

const openAiAdminApiKey = 'REPLACE_WITH_OPENAI_ADMIN_API_KEY';
const monthlyBudgetUsd = 100;

function roundMoney(value) {
  return Math.round(Number(value || 0) * 100) / 100;
}

function monthStartUtc(now) {
  return new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1, 0, 0, 0));
}

function addMonthsUtc(date, months) {
  return new Date(Date.UTC(date.getUTCFullYear(), date.getUTCMonth() + months, 1, 0, 0, 0));
}

function readCostValue(result) {
  return Number(result?.amount?.value ?? result?.amount ?? 0) || 0;
}

if (!openAiAdminApiKey || openAiAdminApiKey.startsWith('REPLACE_WITH_')) {
  return [{ json: { ok: false, status: 'error', error: 'missing_openai_admin_key', reply: 'Falta Admin API key de OpenAI en n8n.' } }];
}

const now = new Date();
const start = monthStartUtc(now);
const nextMonth = addMonthsUtc(start, 1);
const end = now < nextMonth ? now : nextMonth;
const startTime = Math.floor(start.getTime() / 1000);
const endTime = Math.floor(end.getTime() / 1000);

try {
  const data = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.openai.com/v1/organization/costs',
    qs: {
      start_time: startTime,
      end_time: endTime,
      bucket_width: '1d',
      limit: 31
    },
    headers: {
      Authorization: `Bearer ${openAiAdminApiKey}`
    },
    json: true
  });

  const buckets = Array.isArray(data.data) ? data.data : [];
  const spent = buckets.reduce((sum, bucket) => {
    const results = Array.isArray(bucket.results) ? bucket.results : [];
    return sum + results.reduce((inner, result) => inner + readCostValue(result), 0);
  }, 0);

  const currency = String(buckets.flatMap((bucket) => bucket.results || []).find((result) => result?.amount?.currency)?.amount?.currency || 'usd');
  const budget = Number(monthlyBudgetUsd) || 0;
  const remaining = budget ? budget - spent : 0;
  const elapsedMs = Math.max(1, now.getTime() - start.getTime());
  const elapsedDays = elapsedMs / 86400000;
  const dailyAverage = spent / elapsedDays;
  const daysUntilEmpty = budget > 0 && dailyAverage > 0 && remaining > 0 ? remaining / dailyAverage : null;
  const depletionDate = daysUntilEmpty === null ? null : new Date(now.getTime() + daysUntilEmpty * 86400000).toISOString();
  const percentUsed = budget > 0 ? (spent / budget) * 100 : 0;

  return [{
    json: {
      ok: true,
      status: 'ok',
      currency,
      spentUsd: roundMoney(spent),
      budgetUsd: roundMoney(budget),
      remainingUsd: roundMoney(remaining),
      percentUsed: Math.round(percentUsed),
      dailyAverageUsd: roundMoney(dailyAverage),
      daysUntilEmpty: daysUntilEmpty === null ? null : Math.round(daysUntilEmpty * 10) / 10,
      depletionDate,
      periodStart: start.toISOString(),
      periodEnd: end.toISOString(),
      updatedAt: now.toISOString(),
      source: 'openai_organization_costs',
      reply: budget > 0
        ? `Quedan ${roundMoney(remaining)} ${currency.toUpperCase()} de ${roundMoney(budget)}.`
        : `Gastado este mes: ${roundMoney(spent)} ${currency.toUpperCase()}. Configura budget en n8n.`
    }
  }];
} catch (error) {
  const message = error?.response?.body?.error?.message || error?.message || 'openai_costs_error';
  return [{
    json: {
      ok: false,
      status: 'error',
      error: message,
      reply: message.includes('insufficient permissions') || message.includes('Missing scopes')
        ? 'La key de OpenAI necesita scope api.usage.read.'
        : 'No se pudo consultar OpenAI Platform.'
    }
  }];
}
